import React, { Component } from 'react';
import defaultImg from "./image/default.jpg";

class Application extends Component {
    constructor (props) {
        super(props);

        const saveProfile = JSON.parse(localStorage.getItem("userProfile")) || {};
        const saveImg =  localStorage.getItem("profileImg");

        this.state = {
            firstName : saveProfile.firstName || "",
            lastName : saveProfile.lastName || "",
            mobile : saveProfile.mobile || "",
            password : saveProfile.password || "",
            email : saveProfile.email || "",
            regDate : saveProfile.regDate || "",
            add1 : saveProfile.add1 || "",
            add2 : saveProfile.add2 || "",
            province : saveProfile.province || "",
            district : saveProfile.district || "",
            profileImg : saveImg || saveProfile.profileImg || defaultImg,
            showPass : false
        };
        this.fileInputRef = React.createRef();
    }

    handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;
        this.setState({ ...this.state, [name]: value });
    };

    togglePass = () => {
        this.setState({ showPass: !this.state.showPass });
    };

    handleProfileChange = (event) => {
        const file = event.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                localStorage.setItem("profileImg", e.target.result);
                this.setState({ profileImg: e.target.result });
            };
            reader.readAsDataURL(file);
        }
    };

    handleSubmit = (event) => {
        event.preventDefault();
        const requiredFields = [
            "firstName", "lastName", "mobile", "password", "email", "regDate", "add1", "province", "district"
        ];
        for (let field of requiredFields) {
            if (!this.state[field]) {
                alert("⚠️ Please fill all required fields!");
                return;
            }
        }
        localStorage.setItem("userProfile", JSON.stringify(this.state));
        alert("✅ Profile updated successfully!");
    }

    render() { 
        return (
            <div className='background '>
                {/* Left Side */}
                <div className='profile-left transparent-card'>
                    <img 
                        src={this.state.profileImg}
                        alt='Profile'
                        className='profile-image'
                    />
                    <h4>
                        {(this.state.firstName || "") + " " + (this.state.lastName || "") || "Your Name"}
                    </h4>

                    <div className='profile-email'>
                        {this.state.email || "your@email.com"}
                    </div>

                    <input 
                        type='file'
                        accept='image/*'
                        style={{ display: "none" }}
                        ref={this.fileInputRef}
                        onChange={this.handleProfileChange}
                    />
                    <button
                        className='btn btn-primary'
                        onClick={() => this.fileInputRef.current.click()}
                    >
                        Update Image
                    </button>
                </div>

                {/* Right Side */}
                <div className='profile-right transparent-card'>
                    <h3>Profile Settings</h3>
                    <form onSubmit={this.handleSubmit}>
                        <div className='row mb-3'>
                            <div className='col'>
                                <label>First Name</label>
                                <input 
                                    type='text'
                                    className='form-control'
                                    name='firstName'
                                    value={this.state.firstName}
                                    onChange={this.handleChange}
                                />
                            </div>
                            <div className='col'>
                                <label>Last Name</label>
                                <input 
                                    type='text'
                                    className='form-control'
                                    name='lastName'
                                    value={this.state.lastName}
                                    onChange={this.handleChange}
                                />
                            </div>
                        </div>

                        <div className='mb-3'>
                            <label>Mobile</label>
                            <input 
                                type='text'
                                className='form-control'
                                name='mobile'
                                value={this.state.mobile}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className='mb-3' style={{ position: 'relative' }}>
                            <label>Password</label>
                            <input 
                                type={this.state.showPass ? "text" : "password"}
                                className='form-control'
                                name='password'
                                value={this.state.password}
                                onChange={this.handleChange}
                            />
                            <button
                                type='button'
                                className='btn btn-outline-secondary toggle-btn'
                                onClick={this.togglePass}
                            >
                                {this.state.showPass ? "Hide" : "Show"}
                            </button>
                        </div>

                        <div className='mb-3'>
                            <label>Email</label>
                            <input 
                                type='email'
                                className='form-control'
                                name='email'
                                value={this.state.email}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className='mb-3'>
                            <label>Registered Date</label>
                            <input 
                                type='text'
                                className='form-control'
                                name='regDate'
                                value={this.state.regDate}
                                onChange={this.handleChange}
                                placeholder='YYYY-MM-DD HH:MM:SS'
                            />
                        </div>

                        <div className='mb-3'>
                            <label>Address Line 1</label>
                            <input 
                                type='text'
                                className='form-control'
                                name='add1'
                                value={this.state.add1}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className='mb-3'>
                            <label>Address Line 2</label>
                            <input 
                                type='text'
                                className='form-control'
                                name='add2'
                                value={this.state.add2}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className='row mb-3'>
                            <div className='col'>
                                <label>Province</label>
                                <input 
                                    type='text'
                                    className='form-control'
                                    name='province'
                                    value={this.state.province}
                                    onChange={this.handleChange}
                                />
                            </div>
                            <div className='col'>
                                <label>District</label>
                                <input 
                                    type='text'
                                    className='form-control'
                                    name='district'
                                    value={this.state.district}
                                    onChange={this.handleChange}
                                />
                            </div>
                        </div>

                        <button type='submit' className='btn btn-success mt-2'>
                            Update Profile
                        </button>
                    </form>
                </div>
            </div>
        );
    }
}

export default Application;
